    Pfull4 += 16.0 * std::exp((1.0/7.0) * log_y[0] + (8.0/7.0) * log_y[2] + (3.0/2.0) * log_y[3]);
    Pfull4 += 16.0 * std::exp((3.0/7.0) * log_y[0] + (8.0/7.0) * log_y[2] + (3.0/2.0) * log_y[3]);
    Pfull4 += 16.0 * std::exp((4.0/3.0) * log_y[1]);
    Pfull4 += 16.0 * std::exp((2.0/7.0) * log_y[0] + (8.0/3.0) * log_y[1] + 1.0 * log_y[3]);
