    Psimp3 += 1.0 * std::exp((4.0/7.0) * log_y[2] + 1.0 * log_y[3]);

    cx Psimp4(0.0, 0.0);
    Psimp4 += 4.0 * std::exp(0.0);
    Psimp4 += 8.0 * std::exp((4.0/7.0) * log_y[2] + 1.0 * log_y[3]);
    Psimp4 += 4.0 * std::exp((8.0/7.0) * log_y[2] + 2.0 * log_y[3]);
    Psimp4 += (4.0 * params[0]) * std::exp((1.0/3.0) * log_y[4]);
    Psimp4 += (4.0 * params[1]) * std::exp((1.0/3.0) * log_y[4]);
    Psimp4 += (4.0 * params[2]) * std::exp((1.0/3.0) * log_y[4]);
    Psimp4 += (4.0 * params[0]) * std::exp((4.0/7.0) * log_y[2] + 1.0 * log_y[3] + (1.0/3.0) * log_y[4]);
    Psimp4 += (4.0 * params[1]) * std::exp((4.0/7.0) * log_y[2] + 1.0 * log_y[3] + (1.0/3.0) * log_y[4]);
    Psimp4 += (4.0 * params[2]) * std::exp((4.0/7.0) * log_y[2] + 1.0 * log_y[3] + (1.0/3.0) * log_y[4]);
