    Pfull4 += 16.0 * std::exp((2.0/7.0) * log_y[1] + (8.0/3.0) * log_y[2]);

    cx Pfull5(0.0, 0.0);
    Pfull5 += 4.0 * std::exp((4.0/7.0) * log_y[0]);
    Pfull5 += 4.0 * std::exp((4.0/7.0) * log_y[0] + (2.0/7.0) * log_y[1] + (4.0/3.0) * log_y[3]);
