    cx Psimp4(0.0, 0.0);
    Psimp4 += 4.0 * std::exp((8.0/7.0) * log_y[0] + 2.0 * log_y[4]);
    Psimp4 += 8.0 * std::exp((4.0/7.0) * log_y[0] + 2.0 * log_y[4]);
