    Psimp4 += 16.0 * std::exp((4.0/3.0) * log_y[2]);

    cx Psimp5(0.0, 0.0);
    Psimp5 += 4.0 * std::exp((4.0/7.0) * log_y[0]);
    Psimp5 += 4.0 * std::exp(0.0);

    cx full_prod = cx(1.0, 0.0);
