    full_prod *= std::exp((1.0/4.0) * std::log(Pfull1));
    full_prod *= std::exp((1.0/4.0) * std::log(Pfull2));
    full_prod *= std::exp((-3.0/2.0) * std::log(Pfull3));
    full_prod *= std::exp(-5.0 * std::log(Pfull4));
    full_prod *= std::exp(5.0 * std::log(Pfull5));
    cx simp_prod = cx(1.0, 0.0);
    simp_prod *= std::exp((7.0/2.0) * std::log(Psimp0));
    simp_prod *= std::exp((1.0/4.0) * std::log(Psimp1));
    simp_prod *= std::exp((1.0/4.0) * std::log(Psimp2));
    simp_prod *= std::exp((-3.0/2.0) * std::log(Psimp3));
    simp_prod *= std::exp(-5.0 * std::log(Psimp4));
    simp_prod *= std::exp(5.0 * std::log(Psimp5));

    cx yk_factor = std::exp(-1.0 * log_y[1]);
    return (128.0/441.0) * yk_factor * (full_prod - simp_prod);
