    Pfull4 += (4.0 * params[1]) * std::exp((1.0/7.0) * log_y[0] + (1.0/2.0) * log_y[2] + (1.0/3.0) * log_y[3] + 1.0 * log_y[4]);
    Pfull4 += 4.0 * std::exp(2.0 * log_y[4]);
