    Pfull4 += (4.0 * params[2]) * std::exp((2.0/7.0) * log_y[0] + (4.0/3.0) * log_y[1] + 1.0 * log_y[2] + (1.0/3.0) * log_y[3]);
    Pfull4 += 16.0 * std::exp((1.0/7.0) * log_y[0] + (4.0/3.0) * log_y[1] + (1.0/2.0) * log_y[2] + 1.0 * log_y[4]);
